def train_model():
    """Train the spam detection model and save it to disk."""
    texts = [email[0] for email in SAMPLE_EMAILS]
    labels = [email[1] for email in SAMPLE_EMAILS]

    X_train, X_test, y_train, y_test = train_test_split(
        texts, labels, test_size=0.2, random_state=42, stratify=labels
    )

    pipeline = Pipeline([
        ('vectorizer', CountVectorizer(
            lowercase=True,
            stop_words='english',
            max_features=5000,
            ngram_range=(1, 2)
        )),
        ('tfidf', TfidfTransformer()),
        ('classifier', LogisticRegression(
            max_iter=1000,
            C=1.0,
            random_state=42
        ))
    ])

    pipeline.fit(X_train, y_train)

    y_pred = pipeline.predict(X_test)
    print("Model Training Complete!")
    print("=" * 50)
    print(classification_report(
        y_test, y_pred, target_names=["Ham", "Spam"]
    ))

    with open(MODEL_PATH, 'wb') as f:
        pickle.dump(pipeline, f)

    print(f"Model saved to {MODEL_PATH}")
    return pipeline


def load_model():
    """Load the trained model from disk, or train a new one."""
    if os.path.exists(MODEL_PATH):
        with open(MODEL_PATH, 'rb') as f:
            model = pickle.load(f)
        print("Model loaded from disk.")
        return model
    else:
        print("No saved model found. Training new model...")
        return train_model()


# Global model variable
model = None


def get_model():
    """Get the model, loading or training if necessary."""
    global model
    if model is None:
        model = load_model()
    return model


@app.route('/predict', methods=['POST'])
def predict():
    """
    Predict spam probability for given email text.
    
    Expects JSON: {"email_text": "your email content here"}
    Returns JSON with spam probability and classification.
    """
    data = request.get_json()

    if not data or 'email_text' not in data:
        return jsonify({
            'error': 'Missing required field: email_text',
            'usage': 'POST JSON with {"email_text": "your email content"}'
        }), 400

    email_text = data['email_text']

    if not isinstance(email_text, str) or len(email_text.strip()) == 0:
        return jsonify({
            'error': 'email_text must be a non-empty string'
        }), 400

    current_model = get_model()

    probabilities = current_model.predict_proba([email_text])[0]
    prediction = current_model.predict([email_text])[0]

    spam_probability = float(probabilities[1])
    ham_probability = float(probabilities[0])

    result = {
        'email_text': email_text[:200] + ('...' if len(email_text) > 200 else ''),
        'spam_probability': round(spam_probability, 4),
        'ham_probability': round(ham_probability, 4),
        'is_spam': bool(prediction == 1),
        'classification': 'spam' if prediction == 1 else 'ham',
        'confidence': round(max(spam_probability, ham_probability), 4)
    }

    return jsonify(result), 200


@app.route('/predict/batch', methods=['POST'])
def predict_batch():
    """
    Predict spam probability for multiple emails.
    
    Expects JSON: {"emails": ["email1 text", "email2 text", ...]}
    Returns JSON with predictions for each email.
    """
    data = request.get_json()

    if not data or 'emails' not in data:
        return jsonify({
            'error': 'Missing required field: emails',
            'usage': 'POST JSON with {"emails": ["email1", "email2", ...]}'
        }), 400

    emails = data['emails']

    if not isinstance(emails, list) or len(emails) == 0:
        return jsonify({
            'error': 'emails must be a non-empty list of strings'
        }), 400

    if len(emails) > 100:
        return jsonify({
            'error': 'Maximum batch size is 100 emails'
        }), 400

    current_model = get_model()

    probabilities = current_model.predict_proba(emails)
    predictions = current_model.predict(emails)

    results = []
    for i, email_text in enumerate(emails):
        spam_prob = float(probabilities[i][1])
        ham_prob = float(probabilities[i][0])
        pred = int(predictions[i])

        results.append({
            'email_text': email_text[:200] + ('...' if len(email_text) > 200 else ''),
            'spam_probability': round(spam_prob, 4),
            'ham_probability': round(ham_prob, 4),
            'is_spam': bool(pred == 1),
            'classification': 'spam' if pred == 1 else 'ham',
            'confidence': round(max(spam_prob, ham_prob), 4)
        })

    return jsonify({
        'total_emails': len(emails),
        'spam_count': sum(1 for r in results if r['is_spam']),
        'ham_count': sum(1 for r in results if not r['is_spam']),
        'results': results
    }), 200


@app.route('/retrain', methods=['POST'])
def retrain():
    """
    Retrain the model with additional data.
    
    Expects JSON: {"training_data": [{"text": "...", "label": 0}, ...]}
    Labels: 0 = ham, 1 = spam
    """
    global model

    data = request.get_json()

    if not data or 'training_data' not in data:
        return jsonify({
            'error': 'Missing required field: training_data',
            'usage': 'POST JSON with {"training_data": [{"text": "...", "label": 0 or 1}]}'
        }), 400

    training_data = data['training_data']

    # Validate training data
    for item in training_data:
        if 'text' not in item or 'label' not in item:
            return jsonify({
                'error': 'Each training item must have "text" and "label" fields'
            }), 400
        if item['label'] not in [0, 1]:
            return jsonify({
                'error': 'Label must be 0 (ham) or 1 (spam)'
            }), 400

    # Combine with existing data
    all_data = SAMPLE_EMAILS.copy()
    for item in training_data:
        all_data.append((item['text'], item['label']))

    texts = [email[0] for email in all_data]
    labels = [email[1] for email in all_data]

    X_train, X_test, y_train, y_test = train_test_split(
        texts, labels, test_size=0.2, random_state=42, stratify=labels
    )

    pipeline = Pipeline([
        ('vectorizer', CountVectorizer(
            lowercase=True,
            stop_words='english',
            max_features=5000,
            ngram_range=(1, 2)
        )),
        ('tfidf', TfidfTransformer()),
        ('classifier', LogisticRegression(
            max_iter=1000,
            C=1.0,
            random_state=42
        ))
    ])

    pipeline.fit(X_train, y_train)

    accuracy = pipeline.score(X_test, y_test)

    with open(MODEL_PATH, 'wb') as f:
        pickle.dump(pipeline, f)

    model = pipeline

    return jsonify({
        'message': 'Model retrained successfully',
        'total_training_samples': len(all_data),
        'new_samples_added': len(training_data),
        'test_accuracy': round(accuracy, 4)
    }), 200


