@app.route('/model/info', methods=['GET'])
def model_info():
    """Get information about the current model."""
    current_model = get_model()

    vectorizer = current_model.named_steps['vectorizer']
    classifier = current_model.named_steps['classifier']

    feature_names = vectorizer.get_feature_names_out()

    # Get top spam and ham indicator words
    coefficients = classifier.coef_[0]
    top_spam_indices = np.argsort(coefficients)[-10:][::-1]
    top_ham_indices = np.argsort(coefficients)[:10]

    top_spam_words = [
        {'word': feature_names[i], 'weight': round(float(coefficients[i]), 4)}
        for i in top_spam_indices
    ]
    top_ham_words = [
        {'word': feature_names[i], 'weight': round(float(coefficients[i]), 4)}
        for i in top_ham_indices
    ]

    return jsonify({
        'model_type': 'LogisticRegression',
        'feature_extraction': 'CountVectorizer + TfidfTransformer',
        'total_features': len(feature_names),
        'ngram_range': list(vectorizer.ngram_range),
        'top_spam_indicators': top_spam_words,
        'top_ham_indicators': top_ham_words
    }), 200


